  for (let i = 0; i  [p.id, p])).values());

  await browser.close();
  return unique.slice(0, maxItems);
}

// 使用
const items = await scrapeShopee('AirPods Pro', 100);
console.log(`抓到 ${items.length} 個商品`);

// 存 JSON
